public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

@* Collects shipping address fields with validation on Name and Address. *@

<h3>Shipping Information</h3>

<div class="mb-3">
    <label for="name">Name</label>
    <input id="name" class="form-control" @bind="Shipping.Name" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label for="address">Address</label>
    <input id="address" class="form-control" @bind="Shipping.Address" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label for="city">City</label>
    <input id="city" class="form-control" @bind="Shipping.City" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label for="zip">Zip Code</label>
    <input id="zip" class="form-control" @bind="Shipping.ZipCode" @bind:event="oninput" />
</div>

@if (!string.IsNullOrWhiteSpace(validationMessage))
{
    <div class="text-danger mb-2">@validationMessage</div>
}

<button class="btn btn-primary" @onclick="HandleNext">Next</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback<ShippingInfo> ShippingChanged { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    private string? validationMessage;

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name) || string.IsNullOrWhiteSpace(Shipping.Address))
        {
            validationMessage = "Name and Address are required.";
            return;
        }

        validationMessage = null;
        await ShippingChanged.InvokeAsync(Shipping);
        await OnNext.InvokeAsync();
    }
}

@* Collects payment details and exposes Back / Place Order actions. *@

<h3>Payment Information</h3>

<div class="mb-3">
    <label for="card">Card Number</label>
    <input id="card" class="form-control" @bind="Payment.CardNumber" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label for="expiry">Expiry Date</label>
    <input id="expiry" class="form-control" placeholder="MM/YY" @bind="Payment.ExpiryDate" @bind:event="oninput" />
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-success" @onclick="HandlePlaceOrder">Place Order</button>
</div>

@code {
    [Parameter, EditorRequired]
    public PaymentInfo Payment { get; set; } = default!;

    [Parameter]
    public EventCallback<PaymentInfo> PaymentChanged { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnPlaceOrder { get; set; }

    private async Task HandlePlaceOrder()
    {
        await PaymentChanged.InvokeAsync(Payment);
        await OnPlaceOrder.InvokeAsync();
    }
}

@* Orchestrates the checkout steps and owns the Order state. *@

<div class="checkout-wizard">
    @if (step == Step.Shipping)
    {
        <ShippingStep Shipping="order.Shipping"
                      ShippingChanged="OnShippingChanged"
                      OnNext="GoToPayment" />
    }
    else if (step == Step.Payment)
    {
        <PaymentStep Payment="order.Payment"
                     PaymentChanged="OnPaymentChanged"
                     OnBack="GoToShipping"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    /// <summary>Raised when the user completes checkout with a finished order.</summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private enum Step { Shipping, Payment }
    private Step step = Step.Shipping;

    private Order order = new();

    private void OnShippingChanged(ShippingInfo shipping)
    {
        order.Shipping = shipping;
    }

    private void OnPaymentChanged(PaymentInfo payment)
    {
        order.Payment = payment;
    }

    private void GoToPayment() => step = Step.Payment;
    private void GoToShipping() => step = Step.Shipping;

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(order);
    }
}

